import {type FunctionComponent} from "react";
import {type IFilters} from "@lmb-it/kitsconcerto-types";

import {type ColumnFilterElementTemplateOptions} from "primereact/column";

import {Skeleton} from "../../../_compat";
import SliderFilter from "./Filters/SliderFilter";
import TextFilter from "./Filters/TextFilter";
import MultiSelectFilter from "./Filters/MultiSelectFilter";
import ButtonsFilter from "./Filters/ButtonsFilter";
import DropdownFilter from "./Filters/DropdownFilter";
import TriStateFilter from "./Filters/TriStateFilter";
import PhoneFilter from "./Filters/PhoneFilter";
import DateFilter from "./Filters/DateFilter";

export type FilterEl<T = any> = FunctionComponent<
    ColumnFilterElementTemplateOptions & T
>;

export const PickFilterElement: FunctionComponent<{
    filter?: IFilters;
    isLoading: boolean;
    options: ColumnFilterElementTemplateOptions;
    debounceFilterWaitTime: number;
    filterMode: 'enter' | 'debounce';
}> = ({filter, isLoading, options, debounceFilterWaitTime, filterMode}) => {
    if (isLoading) {
        return <Skeleton className={"mb-2"}/>;
    }

    if (filter?.type == "multiSelect") {
        return <MultiSelectFilter list={filter.list} filter={filter.filter} {...options} />;
    } else if (filter?.type == "buttons") {
        return (
            <ButtonsFilter
                list={filter.list}
                isMultiple={filter.isMultiple}
                {...options}
            />
        );
    } else if (filter?.type == "dropdown") {
        return <DropdownFilter list={filter.list} filter={filter.filter} {...options} />;
    } else if (filter?.type == "tristate") {
        return <TriStateFilter {...options} />;
    } else if (filter?.type == "range" || filter?.type == "number") {
        return (
            <SliderFilter
                min={filter.min ?? 0}
                max={filter.max ?? 100}
                debounceFilterWaitTime={debounceFilterWaitTime}
                filterMode={filterMode}
                {...options}
            />
        );
    } else if (filter?.type == "phone") {
        return <PhoneFilter {...options} debounceFilterWaitTime={debounceFilterWaitTime} filterMode={filterMode} />;
    } else if (filter?.type == "date") {
        return <DateFilter {...options} />;
    } else if (filter?.type == "text") {
        return <TextFilter {...options} debounceFilterWaitTime={debounceFilterWaitTime} filterMode={filterMode} />;
    } else {
        return null;
    }
};
